const raw = $json.choices?.[0]?.message?.content || "{}";

const cleaned = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let parsed = {};

try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    intent_score: 50,
    tier: "EXPLORER"
  };
}

return [{
  json: {
    intent_score: Number(parsed.intent_score || 50),
    tier: parsed.tier || "EXPLORER"
  }
}];

